from collections import deque

class Solution:
    def minimumOneBitOperations(self, n):
        if n == 0:
            return 0
        maxbits = 13
        def neighbors(s):
            res = [s ^ 1]
            for i in range(1, maxbits):
                if (s >> (i - 1)) & 1 == 1:
                    mask = (1 << (i - 1)) - 1
                    if (s & mask) == 0:
                        res.append(s ^ (1 << i))
            return res
        dist = {n: 0}
        q = deque([n])
        while q:
            cur = q.popleft()
            if cur == 0:
                return dist[cur]
            for nb in neighbors(cur):
                if nb not in dist:
                    dist[nb] = dist[cur] + 1
                    q.append(nb)
        return -1

